const fs = require('fs');
const rows = $input.all().map(i => i.json);
const today = new Date().toISOString().slice(0, 10);
let md = `# Gov Contracts Review Digest\n\nDate: ${today}\n\nFound **${rows.length}** opportunities.\n\n`;

if (rows.length === 0) {
  md += '_No opportunities matched filters today._\n';
} else {
  for (const r of rows) {
    const deadline = r.response_deadline ? new Date(r.response_deadline).toISOString().slice(0, 10) : 'N/A';
    const link = r.ui_link || '#';
    md += `## ${r.title || 'Untitled'}\n`;
    md += `- **Score:** ${r.rule_score} | **Deadline:** ${deadline}\n`;
    md += `- **Agency:** ${r.agency || 'N/A'} | **NAICS:** ${r.naics || 'N/A'}\n`;
    md += `- **Sol#:** ${r.solicitation_number || 'N/A'} | **Set-aside:** ${r.set_aside || 'None'}\n`;
    md += `- **Reasons:** ${JSON.stringify(r.match_reasons || [])}\n`;
    md += `- [View on SAM.gov](${link})\n\n`;
  }
}

const filePath = `/data/review-digest-${today}.md`;
fs.writeFileSync(filePath, md, 'utf8');

return [{ json: { file_path: filePath, count: rows.length, markdown_preview: md.slice(0, 500) } }];
